"""
MKT Christ Commentary — Job chapters 27–29
Run: python3 scripts/zc-christ-job-27-29.py
Key connections:
- Job 27:4 -> 1 Pet 2:22 / Isa 53:9 (no wickedness in his lips; Christ fulfills the integrity oath)
- Job 28:12 -> 1 Cor 1:30 (where is wisdom? Christ is the answer: God made him our wisdom)
- Job 28:21 -> 1 Cor 2:7-8 (hidden wisdom; rulers didn't know, would not have crucified the Lord of glory)
- Job 28:23 -> John 14:6 / Col 2:3 (God knows wisdom's location; Christ IS the way; all treasures hidden in him)
- Job 28:28 -> Isa 11:2-3 / Heb 5:7 (fear of LORD is wisdom; Christ embodies this perfectly)
- Job 29:3  -> John 8:12 (lamp of God; Christ the light of the world)
- Job 29:12 -> Luke 4:18 (rescued the poor; Christ's messianic program)
- Job 29:15 -> Matt 11:5 / Isa 35:5-6 (eyes for blind, feet for lame; fulfilled literally by Christ)
- Job 29:25 -> Col 1:18 (head, king; Christ preeminent in everything)
"""

import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

new_data = {
    "27": {
        "1": "<p>Job again takes up his discourse &#8212; he has not yet exhausted his case. The persistent advocate who will not be silenced points to Christ, &#8220;who always lives to make intercession&#8221; (Heb&#160;7:25), whose advocacy on behalf of his people never ceases.</p>",
        "2": "<p>&#8220;As God lives, who has denied me justice, and the Almighty, who has made me bitter.&#8221; Job swears by the very God he is accusing &#8212; a paradox of faith inside protest. Christ was truly denied justice at his trial (Pilate: &#8220;I find no fault in him,&#8221; Luke&#160;23:4), yet he submitted to the sentence, bearing the injustice that his people deserved.</p>",
        "3": "<p>&#8220;For as long as my breath remains and God&#8217;s breath is in my nostrils.&#8221; The <i>n&#353;māh</i> of Gen&#160;2:7 &#8212; the divine breath that made man a living being. Christ breathes on the disciples after the resurrection (John&#160;20:22), giving the Holy Spirit: the breath that animated creation now becomes the breath of new creation.</p>",
        "4": "<p>&#8220;My lips will not speak wickedness, and my tongue will not utter deception.&#8221; The integrity oath Job sustains is exactly what Peter says of Christ, citing Isaiah: &#8220;He committed no sin, neither was deceit found in his mouth&#8221; (1&#160;Pet&#160;2:22; Isa&#160;53:9). Christ fulfills perfectly what Job aspires to &#8212; the truly pure witness before God.</p>",
        "5": "<p>&#8220;God forbid that I should agree you are right; until I die I will not surrender my integrity.&#8221; Christ never surrenders his identity under pressure: before the high priest (John&#160;18:37: &#8220;You say that I am a king. For this purpose I was born&#8221;), before Pilate, on the cross &#8212; to his death he does not recant. His integrity is what makes his sacrifice effective.</p>",
        "6": "<p>&#8220;My heart does not condemn me for any of my days.&#8221; The ground for this confidence is ultimately found only in Christ: 1&#160;John&#160;3:20&#8211;21 &#8220;if our heart condemns us, God is greater than our heart&#8221; &#8212; and in Christ Jesus &#8220;there is no condemnation&#8221; (Rom&#160;8:1). Job&#8217;s clear conscience is the imperfect forerunner of the perfect conscience cleansed by Christ&#8217;s blood (Heb&#160;9:14).</p>",
        "7": "<p>Let his enemy be treated as the wicked. Job invokes the eschatological judgment on those who oppose him. Christ does not call down immediate judgment on enemies but promises that the Father will vindicate (Luke&#160;18:7&#8211;8: &#8220;will not God give justice to his elect?&#8221;); final judgment is delegated to the Son (John&#160;5:27).</p>",
        "8": "<p>What hope does the godless man have when God takes away his life? The rhetorical question has its sharpest edge at the cross: the bystanders taunt, &#8220;He trusts in God; let God deliver him now&#8221; (Matt&#160;27:43). But God does deliver &#8212; on the third day &#8212; showing that the hope of the righteous outlasts death itself.</p>",
        "9": "<p>Will God hear the cry of the godless when trouble comes? Contrast with Christ&#8217;s cry from the cross (Ps&#160;22:1, &#8220;My God, my God, why have you forsaken me?&#8221;) which God does hear &#8212; Ps&#160;22:24 &#8220;he has not despised or scorned the suffering of the afflicted one; he has not hidden his face from him but has listened to his cry for help.&#8221;</p>",
        "10": "<p>Does the godless man take delight in the Almighty or call on him? Christ is the one who always delights in the Father (John&#160;5:19: &#8220;the Son can do nothing of himself, but only what he sees the Father doing; for whatever the Father does, the Son does likewise&#8221;) and prays without ceasing (Luke&#160;5:16: &#8220;he would withdraw to desolate places and pray&#8221;).</p>",
        "11": "<p>&#8220;I will instruct you about the hand of God; I will not hide what the Almighty has shown me.&#8221; This is precisely what Christ does: John&#160;1:18 &#8220;no one has ever seen God; the only-begotten Son, who is in the Father&#8217;s presence, has made him known.&#8221; Christ is the revealer who does not hide what the Father has shown him (John&#160;15:15).</p>",
        "12": "<p>&#8220;You yourselves have seen all this; why then have you become so thoroughly empty?&#8221; The friends&#8217; empty theology is a warning against religion that has lost its center. Paul warns against those who have &#8220;the appearance of godliness but deny its power&#8221; (2&#160;Tim&#160;3:5); Christ is the power-content that hollow religion lacks.</p>",
        "13": "<p>The lot God assigns the wicked; the inheritance oppressors receive. The eschatological judgment Job describes here is what Christ proclaims: Matt&#160;25:41 &#8220;depart from me, you cursed, into the eternal fire prepared for the devil and his angels.&#8221; Judgment and mercy are both in Christ&#8217;s hands (John&#160;5:22).</p>",
        "14": "<p>If his children multiply, it is only for the sword; his descendants will not have enough to eat. The reversal of the wicked man&#8217;s apparent prosperity is a theme Christ extends: Luke&#160;12:20 &#8220;fool! This night your soul is required of you.&#8221; The accumulation of the ungodly is reversed by death.</p>",
        "15": "<p>His survivors buried by plague; his widows will not weep. The unmourned death contrasts with Christ who wept at Lazarus&#8217;s tomb (John&#160;11:35) and showed that death is worthy of grief &#8212; and also worthy of being reversed by resurrection.</p>",
        "16": "<p>He piles up silver like dust and lays up clothing as plentiful as clay. The futility of hoarded wealth is what Christ teaches directly: Luke&#160;12:15&#8211;21 (parable of the rich fool: &#8220;be on your guard against all covetousness, for one&#8217;s life does not consist in the abundance of possessions&#8221;).</p>",
        "17": "<p>He stores it, but the righteous man will wear it; the innocent will share out the silver. The great reversal: the accumulated wealth of the wicked benefits the righteous. In Christ this pattern is enacted cosmically: he who was rich became poor so that through his poverty the many might become rich (2&#160;Cor&#160;8:9).</p>",
        "18": "<p>He builds his house as a moth builds its web, like a watchman&#8217;s temporary shelter. The fragility of the ungodly&#8217;s house anticipates Christ&#8217;s parable of the wise and foolish builders (Matt&#160;7:24&#8211;27): only the house built on Christ&#8217;s words survives the storm. The moth&#8217;s web stands in contrast to the eternal house Christ is building (John&#160;14:2).</p>",
        "19": "<p>The rich man lies down, is not gathered to his ancestors; opens his eyes, and is gone. The sudden dissolution of the wicked. Luke&#160;16:22&#8211;23 (Lazarus and the rich man): the reversal comes at death; the rich man&#8217;s security evaporates as Job describes.</p>",
        "20": "<p>Terrors sweep over him like a flood; a storm carries him off in the night. The sudden judgment-flood echoes the great flood pattern (Matt&#160;24:37&#8211;39) and the unprepared day of the Lord (1&#160;Thes&#160;5:2&#8211;3: &#8220;destruction will come on them suddenly&#8221;). Christ&#8217;s return catches the unprepared like such a storm.</p>",
        "21": "<p>The east wind sweeps him away; a storm flings him from his home. The storm of divine judgment. Christ himself commands the storm (Mark&#160;4:39) and will come in power like lightning from east to west (Matt&#160;24:27) &#8212; both master of the storm and the judge it represents.</p>",
        "22": "<p>God hurls his power at him without mercy; the man desperately flees. The full weight of divine power against the unrepentant wicked &#8212; the judgment that Christ himself bore in the place of his people on the cross (Isa&#160;53:10: &#8220;it was the will of the LORD to crush him&#8221;), so that mercy rather than mercilessness might reach those who trust him.</p>",
        "23": "<p>Men clap their hands and hiss him away from his home. The derisive reception: exactly what happened at the crucifixion (Matt&#160;27:39: &#8220;those passing by derided him, wagging their heads&#8221;; Lam&#160;2:15: &#8220;all who pass by clap their hands at you&#8221;). Christ absorbed what the wicked deserved &#8212; the clapping and hissing of contempt &#8212; and turned it into the occasion of redemption.</p>"
    },
    "28": {
        "1": "<p>Surely silver has its mine and gold a place where it is refined. The wisdom poem opens with humanity&#8217;s impressive capacity to find hidden things in the earth &#8212; setting up the contrast with what human ingenuity cannot locate: wisdom itself. Col&#160;2:3 names the answer: all the treasures of wisdom and knowledge are hidden in Christ.</p>",
        "2": "<p>Iron is taken from the earth, copper smelted from ore. The catalogue of human mining achievement &#8212; iron smelting marks the Bronze-to-Iron Age transition (Gen&#160;4:22; 1&#160;Sam&#160;13:19) &#8212; but none of these discovered metals equals wisdom. Christ crucified is the power and wisdom of God that surpasses every earthly resource (1&#160;Cor&#160;1:24).</p>",
        "3": "<p>A miner sets a limit to the darkness and searches to its utmost depth. The miner penetrates where no light reaches. Christ &#8220;descended into the lower parts of the earth&#8221; (Eph&#160;4:9) &#8212; the one who descended also ascended, carrying with him those he rescued from the deepest dark (Eph&#160;4:8).</p>",
        "4": "<p>Far from where people live, a shaft is sunk; miners dangle, forgotten by travelers&#8217; feet. The solitary, hidden labor of the miner &#8212; the isolation and hiddenness of redemptive work. Christ&#8217;s agony in Gethsemane (while the disciples slept, Matt&#160;26:40) and the hours on the cross were similarly hidden and unnoticed in their full weight.</p>",
        "5": "<p>The earth produces bread on its surface but underneath is turned up as by fire. The surface yields bread; below, fire and stone. Christ is both: the bread of life (John&#160;6:35) on the surface of ordinary human existence, and the consuming fire of God&#8217;s holiness beneath (Heb&#160;12:29) &#8212; both nourisher and refiner.</p>",
        "6": "<p>Its stones are the source of sapphires and it holds flakes of gold. The hidden beauty of the earth&#8217;s depths anticipates what Isa&#160;54:11&#8211;12 promises for the new creation &#8212; the city built of precious stones &#8212; fulfilled in the new Jerusalem whose foundations are adorned with every precious stone (Rev&#160;21:19&#8211;20).</p>",
        "7": "<p>A path no bird of prey knows, unseen by the falcon&#8217;s eye. The miner&#8217;s path is hidden from the most sharp-eyed creatures. The path of wisdom likewise is hidden from natural perception: 1&#160;Cor&#160;2:14 &#8220;the natural person does not accept the things of the Spirit of God; they are foolishness to him, and he is not able to understand them.&#8221;</p>",
        "8": "<p>The lion&#8217;s cubs have not walked it; the fierce lion has not passed over it. Even the king of beasts has not found wisdom&#8217;s path. Christ the Lion of Judah (Rev&#160;5:5) is the one who walks wisdom&#8217;s path &#8212; and who is himself that path (John&#160;14:6: &#8220;I am the way, the truth, and the life&#8221;).</p>",
        "9": "<p>He puts his hand to the flint and uproots mountains from their foundations. Human ingenuity moves mountains &#8212; yet wisdom cannot be quarried. Christ says faith like a mustard seed can move mountains (Matt&#160;17:20) &#8212; but the wisdom that saves is not a human achievement at all; it is the gift of God revealed in his Son.</p>",
        "10": "<p>He cuts channels through the rocks; his eye takes in every precious thing. The penetrating human gaze that sees every precious mineral &#8212; yet misses wisdom. Christ&#8217;s eye sees what humans miss: he sees the tax collector in the tree, the widow giving her last coin, the faith of the centurion. His perception is the true vision.</p>",
        "11": "<p>He holds back the streams from seeping through and brings hidden things out to the light. Human ingenuity makes the hidden visible. Christ brings the ultimate hidden thing to light: 1&#160;Cor&#160;2:7 &#8220;we speak God&#8217;s wisdom in a mystery, which God predestined before the ages for our glory,&#8221; hidden and now revealed in Christ crucified.</p>",
        "12": "<p>&#8220;But where shall wisdom be found? And where is the place of understanding?&#8221; The central question of the poem &#8212; and of the whole book. 1&#160;Cor&#160;1:30 gives the NT answer: &#8220;Christ Jesus, whom God made our wisdom, righteousness, sanctification, and redemption.&#8221; The question finds its answer not in a location but in a person.</p>",
        "13": "<p>No mortal knows the path to wisdom; it is not found in the land of the living. Human wisdom-seeking, however sincere, cannot locate divine wisdom by its own resources. Jn&#160;1:18 &#8220;no one has ever seen God&#8221; &#8212; the inaccessible wisdom becomes accessible only through the one who comes from God and goes to God (John&#160;13:3).</p>",
        "14": "<p>The deep says &#8220;It is not in me,&#8221; and the sea says &#8220;It is not with me.&#8221; The primordial waters &#8212; the chaos forces of Gen&#160;1:2 &#8212; disclaim wisdom. Christ walks on the water (Matt&#160;14:25) and calms the sea (Mark&#160;4:39) &#8212; he is not found in the chaos; he commands it. And the wisdom that transcends the deep was incarnated in him.</p>",
        "15": "<p>Wisdom cannot be bought with gold or paid for in silver. Not by the most valuable human currency. Yet 1&#160;Pet&#160;1:18&#8211;19 says we &#8220;were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold, but with the precious blood of Christ.&#8221; Wisdom came at an incalculable price &#8212; not human currency but divine self-giving.</p>",
        "16": "<p>It cannot be matched against the gold of Ophir, the precious onyx, or the sapphire. All the treasures of ancient trade routes are insufficient. The &#8220;unsearchable riches of Christ&#8221; (Eph&#160;3:8) exceed every comparison &#8212; Paul&#8217;s exact phrase echoes the wisdom poem&#8217;s language of incomparability.</p>",
        "17": "<p>Gold and crystal cannot match wisdom&#8217;s worth; no item of fine gold can be exchanged for it. The absolute incomparability of wisdom: Phil&#160;3:8 &#8220;I count everything as loss because of the surpassing worth of knowing Christ Jesus my Lord.&#8221; What Job&#8217;s poem declares about wisdom, Paul declares about Christ &#8212; because Christ is that wisdom.</p>",
        "18": "<p>Coral and crystal not worth mentioning; the value of wisdom is above rubies. The catalogue of priceless things exhausted &#8212; wisdom exceeds them all. So the kingdom of heaven is like a merchant seeking fine pearls who, finding one pearl of great price, sells everything he has (Matt&#160;13:45&#8211;46). Christ is that pearl.</p>",
        "19": "<p>The topaz of Cush cannot compare with wisdom; it cannot be priced against pure gold. The rhetorical exhaustion of comparisons forces the conclusion: wisdom is in a category of its own. So Christ, as divine wisdom, is incommensurable with any human achievement or value &#8212; his &#8220;excellency&#8221; (Phil&#160;4:7) surpasses all understanding.</p>",
        "20": "<p>&#8220;Where then does wisdom come from? And where is the place of understanding?&#8221; The question repeated with more urgency. John&#160;1:1&#8211;4: &#8220;In the beginning was the Word... In him was life, and the life was the light of men.&#8221; The Word who became flesh (John&#160;1:14) is wisdom&#8217;s address; the Incarnation is wisdom&#8217;s location.</p>",
        "21": "<p>Wisdom is hidden from the eyes of every living creature, kept from the birds of the sky. 1&#160;Cor&#160;2:7&#8211;8: &#8220;we speak God&#8217;s wisdom in a mystery, which God predestined before the ages for our glory. None of the rulers of this age understood this, for if they had, they would not have crucified the Lord of glory.&#8221; The hidden wisdom became visible in Christ crucified &#8212; hidden from the powerful, revealed to the humble (Matt&#160;11:25).</p>",
        "22": "<p>Abaddon and Death say, &#8220;We have heard only a rumor of wisdom.&#8221; Even the realm of the dead has only a whisper. But Christ holds the keys of death and Hades (Rev&#160;1:18) &#8212; he has gone where Abaddon only heard rumor, has conquered what death only knew by reputation, and has brought wisdom&#8217;s full reality to light through the gospel (2&#160;Tim&#160;1:10).</p>",
        "23": "<p>&#8220;God understands the way to wisdom and knows its location.&#8221; John&#160;14:6: &#8220;I am the way, the truth, and the life. No one comes to the Father except through me.&#8221; Christ does not merely know where wisdom is; he is wisdom&#8217;s place. And Col&#160;2:3: &#8220;in him are hidden all the treasures of wisdom and knowledge&#8221; &#8212; God&#8217;s location of wisdom is the person of his Son.</p>",
        "24": "<p>He looks to the ends of the earth and sees everything under all of heaven. God&#8217;s omniscient gaze that encompasses the creation. Heb&#160;4:13: &#8220;no creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account.&#8221; In Christ the all-seeing God has also looked on human suffering from the inside (John&#160;11:35).</p>",
        "25": "<p>When he assigned a weight to the wind and measured the waters. God the precise orderer of creation: the wind has weight, the waters have measure. Christ, through whom all things were made (John&#160;1:3), is the one who assigned these measures; and the one who calms the wind (Mark&#160;4:39) knew its weight from within creation.</p>",
        "26": "<p>When he established a decree for the rain and a path for the lightning and thunder. Creation&#8217;s order is the expression of divine wisdom. Col&#160;1:17: &#8220;in him all things hold together&#8221; &#8212; the coherence of the natural order is sustained by Christ, the living decree that orders creation.</p>",
        "27": "<p>&#8220;Then he saw wisdom and made it known; he established it and fully searched it out.&#8221; The &#8220;making known&#8221; of wisdom is the defining event &#8212; and it is the Incarnation. Heb&#160;1:1&#8211;2: &#8220;in these last days he has spoken to us by his Son.&#8221; Col&#160;1:26&#8211;27: &#8220;the mystery hidden for ages... now disclosed: Christ in you, the hope of glory.&#8221; The search ends in the revealed Son.</p>",
        "28": "<p>&#8220;The fear of the Lord is wisdom; to turn from evil is understanding.&#8221; The poem&#8217;s conclusion. Isa&#160;11:2&#8211;3 says the Spirit of the LORD who will rest on the Messiah includes &#8220;the spirit of the fear of the LORD.&#8221; Heb&#160;5:7: Jesus offered prayers &#8220;and was heard because of his reverence.&#8221; Christ embodies this definition &#8212; the perfectly God-fearing, evil-rejecting man who is himself divine wisdom (1&#160;Cor&#160;1:24, 30).</p>"
    },
    "29": {
        "1": "<p>Job continues his discourse. The nostalgia speech that follows is both Job&#8217;s most poignant personal reflection and an unwitting portrait of the righteous servant. Every quality Job recalls as lost is permanently secured in and through Christ.</p>",
        "2": "<p>&#8220;Oh that I were as in the months gone by, in the days when God watched over me.&#8221; The longing for restored divine fellowship. Heb&#160;13:8: &#8220;Jesus Christ is the same yesterday, today, and forever.&#8221; In Christ, the fellowship with God that Job nostalgically recalls is not restored to a former state but established permanently on an unbreakable foundation.</p>",
        "3": "<p>&#8220;When his lamp shone on my head and by his light I walked through darkness.&#8221; John&#160;8:12: &#8220;I am the light of the world; whoever follows me will not walk in darkness but will have the light of life.&#8221; Christ is the lamp Job remembers &#8212; and the promise of that lamp is now made unconditional and eternal in the one who is himself the light.</p>",
        "4": "<p>&#8220;When the friendship of God rested upon my tent.&#8221; John&#160;15:15: &#8220;No longer do I call you servants... I have called you friends.&#8221; The friendship of God that Job experienced in his prosperity is restored and made permanent through Christ, who makes the Father&#8217;s friendship available to all his people. Rev&#160;21:3: &#8220;God&#8217;s dwelling place is with man.&#8221;</p>",
        "5": "<p>&#8220;When the Almighty was still with me, and my children were gathered around me.&#8221; Heb&#160;2:10&#8211;13: Christ &#8220;bringing many sons to glory... Here am I and the children God has given me.&#8221; Christ is the elder brother who gathers the children into the Father&#8217;s presence. Matt&#160;18:20: &#8220;where two or three are gathered in my name, I am there among them.&#8221;</p>",
        "6": "<p>&#8220;When I bathed my steps in cream and the rock poured out streams of oil for me.&#8221; The abundant provision Job nostalgizes. 1&#160;Cor&#160;10:4: the Israelites &#8220;drank from the spiritual Rock that followed them, and the Rock was Christ&#8221; &#8212; the rock that poured streams in the wilderness is Christ; and John&#160;10:10 promises the abundant life Job describes.</p>",
        "7": "<p>When I went out to the city gate and took my seat in the public square. The city gate as the place of justice, community, and honor. Christ &#8220;went out&#8221; fully &#8212; into the public square of human life &#8212; not to receive honor but to give himself (Mark&#160;10:45). And Phil&#160;2:10&#8211;11 promises the honor at the name of Jesus that exceeds every gate&#8217;s recognition.</p>",
        "8": "<p>The young men saw me and stepped aside; the aged rose and stood to their feet. The universal honor Job received. Phil&#160;2:10: &#8220;at the name of Jesus every knee shall bow, in heaven and on earth and under the earth.&#8221; The honor Job recalls is the imperfect anticipation of the perfect homage that will one day be Christ&#8217;s from every creature.</p>",
        "9": "<p>The princes stopped speaking and covered their mouths with their hands. The silence of the powerful before Job. Isa&#160;52:15 &#8212; applied to the Servant: &#8220;kings shall shut their mouths because of him; for that which has not been told them they see.&#8221; The ones who silenced Jesus before the crucifixion will themselves be silenced in awe at his revelation (Rev&#160;1:17).</p>",
        "10": "<p>The voice of the nobles fell silent; their tongues stuck to the roof of their mouths. The silence before wisdom incarnate. Matt&#160;22:46: &#8220;no one was able to answer him a word, nor from that day did anyone dare to ask him any more questions.&#8221; When Christ speaks, the wise fall silent because wisdom itself is present.</p>",
        "11": "<p>For the ear that heard me called me blessed, and the eye that saw me testified for me. The double beatitude of hearing and seeing: Luke&#160;10:23&#8211;24: &#8220;Blessed are the eyes that see what you see! For I tell you that many prophets and kings desired to see what you see, and did not see it, and to hear what you hear, and did not hear it.&#8221; Christ is the one for whom hearing and seeing are ultimate blessing.</p>",
        "12": "<p>&#8220;For I rescued the poor when they cried for help, and the fatherless who had no one to help them.&#8221; Luke&#160;4:18: &#8220;The Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor.&#8221; Job&#8217;s rescue ministry is the exact pattern of Christ&#8217;s messianic program &#8212; announced by Jesus as his own mission statement.</p>",
        "13": "<p>&#8220;The blessing of the one about to perish came to me, and I made the widow&#8217;s heart sing for joy.&#8221; Luke&#160;7:12&#8211;15: Christ raises the widow of Nain&#8217;s son and &#8220;gave him to his mother.&#8221; He made the widow&#8217;s heart sing in the most literal sense &#8212; through resurrection. The joy Job gave is the shadow of the joy Christ alone can fully give.</p>",
        "14": "<p>&#8220;I put on righteousness and it clothed me; my justice was like a robe and a turban.&#8221; Gal&#160;3:27: &#8220;as many of you as were baptized into Christ have put on Christ.&#8221; The righteousness Job wore as his character is the righteousness God now gives through Christ &#8212; not earned but imputed, not worn as achievement but received as gift (Phil&#160;3:9).</p>",
        "15": "<p>&#8220;I was eyes for the blind and feet for the lame.&#8221; Matt&#160;11:5: &#8220;the blind receive their sight and the lame walk.&#8221; Christ literally fulfills the Isaianic messianic sign (Isa&#160;35:5&#8211;6). Job&#8217;s metaphorical service to the disabled anticipates Christ&#8217;s direct miraculous service that signals the kingdom&#8217;s arrival.</p>",
        "16": "<p>&#8220;I was a father to the needy, and I investigated the case of the one I did not know.&#8221; Ps&#160;68:5: &#8220;Father of the fatherless and protector of widows is God in his holy habitation.&#8221; Christ as the one who embodies the Father&#8217;s care (John&#160;14:9: &#8220;whoever has seen me has seen the Father&#8221;); and John&#160;5:22 the authority to judge every case is given to the Son.</p>",
        "17": "<p>&#8220;I broke the fangs of the wicked and forced the prey from his teeth.&#8221; Heb&#160;2:14: &#8220;through death he destroyed the one who has the power of death, that is, the devil.&#8221; Col&#160;2:15: &#8220;he disarmed the rulers and authorities and put them to open shame.&#8221; The breaking of the wicked one&#8217;s fangs is enacted at the cross &#8212; the prey wrenched free from death&#8217;s grip.</p>",
        "18": "<p>&#8220;Then I said, I shall die in my own nest and multiply my days like the sand.&#8221; The confidence of a long and peaceful life. Christ &#8220;died in his nest&#8221; in a different sense &#8212; on the cross, at the center of his calling &#8212; and his days are multiplied beyond sand: &#8220;I have the keys of Death and Hades&#8221; (Rev&#160;1:18); &#8220;I am alive forevermore.&#8221;</p>",
        "19": "<p>&#8220;My roots spread out to the waters and the dew rested all night on my branches.&#8221; John&#160;15:5: &#8220;I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit.&#8221; The fruitful tree watered at the root is fulfilled in Christ the true Vine whose branches draw life from his resurrection-life.</p>",
        "20": "<p>&#8220;My glory remained fresh within me; and my bow was always renewed in my hand.&#8221; 2&#160;Cor&#160;4:16: &#8220;though our outer self is wasting away, our inner self is being renewed day by day.&#8221; The renewal Job experienced in his prime is the renewal Christ makes permanent through the Spirit &#8212; and Isa&#160;40:31 (those who wait on the LORD renew their strength) finds its ground in Christ&#8217;s own resurrection.</p>",
        "21": "<p>Men listened to me and waited; they held their silence for my counsel. The reverent silence before one whose words were life-giving. John&#160;6:68: &#8220;Lord, to whom shall we go? You have the words of eternal life.&#8221; The disciples stayed, listening, because no one else spoke with the authority of life that Christ possessed.</p>",
        "22": "<p>After my words they spoke no more; my speech fell upon them. The finality of words that settle every question. Heb&#160;1:2: God &#8220;has spoken to us by his Son&#8221; &#8212; and this final word supersedes all previous words; after Christ speaks, there is nothing more that needs to be said about God&#8217;s saving purpose.</p>",
        "23": "<p>They waited for me as for the rain and opened their mouths wide as for the spring rain. John&#160;7:37&#8211;38: &#8220;on the last day of the feast, Jesus stood up and cried out, &#8216;If anyone thirsts, let him come to me and drink. Whoever believes in me, as the Scripture has said, out of his heart will flow rivers of living water.&#8217;&#8221; The people opening wide for rain are the image Christ fulfills at the feast of Tabernacles.</p>",
        "24": "<p>&#8220;When I smiled at them they could hardly believe it; they did not let the light of my face fall to the ground.&#8221; 2&#160;Cor&#160;4:6: &#8220;God, who said &#8216;Let light shine out of darkness,&#8217; has shone in our hearts to give the light of the knowledge of the glory of God in the face of Jesus Christ.&#8221; The light of Job&#8217;s face is the anticipation of the transforming light of Christ&#8217;s face that gives the knowledge of God&#8217;s glory.</p>",
        "25": "<p>&#8220;I chose the course for them and sat as their head; I lived as a king among his troops, as one who comforts mourners.&#8221; Col&#160;1:18: &#8220;he is the head of the body, the church; he is the beginning, the firstborn from the dead, that in everything he might be preeminent.&#8221; Job as shepherd-king-comforter among his community is the type; Christ the head, king, and comforter of mourners (Matt&#160;5:4; John&#160;14:26) is the antitype.</p>"
    }
}

existing = load_comm('mkt-christ', 'job')
merge_comm(existing, new_data)
save_comm('mkt-christ', 'job', existing)

for ch in sorted(new_data.keys(), key=int):
    vv = new_data[ch]
    have = sum(1 for v in vv if v in existing.get(ch, {}))
    print(f'  ch{ch}: {have}/{len(vv)} verses present')
